var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저…… 토토도 같이 왔는데, 괜찮지?","JPN":"あの……トトも一緒に来ているけど、大丈夫だよね？","ENG":"Umm... Toto tagged along. That’s okay, right?","TWN":"那個……托托可以跟我一起來吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"미리 감자튀김을 배부르게 먹여 뒀으니까 난리 피우진 않을 거야.","JPN":"念のため、フライドポテトをお腹いっぱい食べさせておいたから、大人しくしてくれると思う。","ENG":"I fed him a lot of french fries, so he won't misbehave.","TWN":"我已經有先用薯條餵飽它，應該不會有問題。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토랑 같이 언더그라운드를 떠돌면서 느낀 게 있어.","JPN":"トトと一緒にアンダーグラウンドを回って感じたことがあるんだ。","ENG":"I realized something while wandering the Underground with Toto.","TWN":"我和托托在地下世界流浪時發現一件事，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"서로를 믿지 못하고 살아가는 게 얼마나 불행한 일인지.","JPN":"お互いを信じられずに生きていくことが、どれほど不幸なことなのか。","ENG":"It’s such an unfortunate thing to live without being able to trust each other.","TWN":"就是生活中如果無法彼此信任，這是一件多麼悲慘的事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그런 면에서 나는 운이 좋지.","JPN":"そういう意味では私は運がいいね。","ENG":"In that sense, I’m lucky.","TWN":"這麼看來我真的是很幸運呢！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"믿을 수 있는 친구들이 있으니까.","JPN":"信じられる友達がいるから。","ENG":"Since I have friends that I can trust.","TWN":"有一群可以信任的朋友。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"게다가 너도…… 혹시라도 내가 안심하지 못할까 봐, 이런 것까지 해 준다는 거잖아?","JPN":"それにあなたも……私が不安がっていると思って、こんなことまでしてくれたってことでしょ？","ENG":"Also... You did all of this, just in case I wouldn’t be able to be at ease, right?","TWN":"還有你……你也是怕我不放心，才刻意這麼做的吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"종신이니 계약이니 그런 무서운 단어를 썼지만, 평생 친구 하자는 얘기인 거 알아.","JPN":"終身とか契約とか、そんな怖そうな単語を使ってたけど、一生の友達になろうっていう意味なんだよね？","ENG":"You used scary words such as Lifetime and contract, but I know that you mean you want to be friends with me forever.","TWN":"終身契約聽起來好像很可怕，但我知道你意思是要和我當一輩子的朋友！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그리고 토토도…… 편견 없이 봐 주는 거 다 알고 있어.","JPN":"それにトトも……偏見なく見てくれることを全部わかってるんだ。","ENG":"And also Toto... I know you’re viewing him without prejudice.","TWN":"而且……我知道你對托托也沒有偏見。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"매일 토토를 빼앗아 가려는 사람들이랑 싸우는 것도, 토토를 무서워하는 사람들을 피해 뒷골목을 전전하는 것도 사실은 힘들었는데.","JPN":"毎日トトを奪おうとする人たちと戦うのも、トトを怖がる人たちを避けて路地裏を転々とするのも、実は辛かったの。","ENG":"To be honest, it was difficult having to fight everyday against people who were trying to steal away Toto, and to wander the alleyways to avoid people who were afraid of him.","TWN":"說真的，每天要應付那些想搶走托托的人，或是怕人家看到托托會嚇到，必須躲到小巷子裡生活，這些事真的很累人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"너를 만나서, 너랑 친구 할 수 있어서 정말 다행이라고 생각해.","JPN":"あなたに出会えて、あなたと友達になれて本当に良かったと思ってる。","ENG":"But, I think I'm really lucky to have met you, and to be friends with you.","TWN":"遇到你之後，覺得可以跟你當朋友真的是超幸運的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};